<template>
  <div id="mvt">
    <iframe :src="url"></iframe>
    <div class="mvt_intro">
      <h2>使用方法：</h2>
      <p>将pbf文件拖拽到左边区域内，将会绘制出该pbf文件的内容.</p>
      <p>关于该pbf文件的图层信息，按F12，在控制台中可以看到它的内容.</p>
    </div>
  </div>
</template>

<script>
  export default {
    name: 'app',
    data () {
      return {
          url: "static/tools/mvtProcess/index.html"
      }
    },
    methods:{
    },
    mounted(){
    }
  }
</script>

<style>
  #mvt{
    height: 100%;
    width: 100%;
    text-align: left;
  }
  iframe{
    height: 100%;
    width: 70%;
    float: left;
  }
  .mvt_intro{
    padding: 15px;
    height: 100%;
    width: 25%;
    float: left;
  }
</style>



