<template>
  <div id="app">
    <header>
      <div @click="goHome()">Magic World </div>
      <!--<div style="float: right;width: 100px;cursor: pointer">Tools</div>-->
    </header>
    <main>
      <router-view></router-view>
    </main>
  </div>
</template>

<script>
export default {
  name: 'app',
  data () {
    return {
    }
  },
  methods:{
    goHome(){
      this.$router.push('/');
    }
  },
}
</script>

<style>
  @font-face {
    font-family: 'Gloria Hallelujah';
    font-style: normal;
    font-weight: 400;
    font-display: fallback;
    src: local('Gloria Hallelujah'), local('GloriaHallelujah'), url(./assets/fonts/font.woff2) format('woff2');
    unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+2000-206F, U+2074, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
  }
body {
  margin: 0;
  font-family: 'Gloria Hallelujah', sans-serif;
  position: absolute;
  width: 100%;
  height: 100%;
}

#app {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  color: #2c3e50;
  position: absolute;
  width: 100%;
  height: 100%;
}

main {
  text-align: center;
  width: 100%;
  height: 92%;
}

header {
  margin: 0;
  height: 8%;
  padding: 12px 16px 0 24px;
  background-color: #35495E;
  color: #ffffff;
}
  header div {
    height: 100%;
    width: 200px;
    font-size: 20px;
    cursor: pointer;
  }
</style>



