<template>
  <div id="tools">
    <el-col class="tools_nav">
      <el-menu
        style="height: 100%"
        default-active="1-1"
        background-color="#545c64"
        text-color="#fff"
        active-text-color="#ffd04b">
        <el-submenu index="1">
          <template slot="title">
            <i class="el-icon-location"></i>
            <span class="tools_nav_title">MBTiles</span>
          </template>
          <el-menu-item-group>
            <el-menu-item index="1-1" @click="goto('/tools/mvt')">pbf文件查看器</el-menu-item>
          </el-menu-item-group>
        </el-submenu>
        <el-menu-item index="2">
          <i class="el-icon-menu"></i>
          <span slot="title" class="tools_nav_title">glTF</span>
        </el-menu-item>
        <el-menu-item index="3">
          <i class="el-icon-document"></i>
          <span slot="title" class="tools_nav_title">3D Tiles</span>
        </el-menu-item>
        <el-menu-item index="4">
          <i class="el-icon-setting"></i>
          <span slot="title" class="tools_nav_title">GeoJSON</span>
        </el-menu-item>
      </el-menu>
    </el-col>
    <el-col class="tools_main">
      <router-view></router-view>
    </el-col>
  </div>
</template>

<script>
  export default {
    name: 'gallery',
    data () {
      return {

      }
    },
    methods: {
      goto(path){
          this.$router.push(path)
      }
    }
  }
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  /*#tools>div{*/
    /*width: 300px;*/
    /*height: 400px;*/
    /*!*margin: 20px;*!*/
  /*}*/
  #tools{
    height: 100%;
    width: 100%;
  }
  .tools_nav{
    width: 17%;
    height: 100%;
  }
  .tools_main{
    width: 83%;
    height: 100%;
  }
  /*.tools_nav_title{*/
    /*width: 20px;*/
  /*}*/
</style>



