<template>
  <div id="hello">
    <div style="padding-top: 80px">
      <h1>Welcome to My Magic World!</h1>
      <wired-button @click="enter(0)">Enter</wired-button>
    </div>
    <div style="padding-top: 80px">
      <h1>Go to Tools!</h1>
      <wired-button @click="enter(1)">Enter</wired-button>
    </div>
    <div id="background"></div>
  </div>
</template>

<script>
  import '../js/renderers/Projector.js'
  import '../js/renderers/CanvasRenderer.js'
  import {WiredButton, WiredInput} from "wired-elements"
  export default {
    name: 'hello',
    data () {
      return {
        msg: 'Welcome to My Magic World! '
      }
    },
    methods:{
        enter(index){
            switch (index){
              case 0:
                this.$router.push('/gallery');
                break;
              case 1:
                this.$router.push('/tools/mvt');
                break;
            }
        }
    },
    mounted(){

      var container;
      var camera, scene, renderer;

      var raycaster;
      var mouse;

      var PI2 = Math.PI * 2;

      var programFill = function (context) {

        context.beginPath();
        context.arc(0, 0, 0.5, 0, PI2, true);
        context.fill();

      };

      var programStroke = function (context) {

        context.lineWidth = 0.025;
        context.beginPath();
        context.arc(0, 0, 0.5, 0, PI2, true);
        context.stroke();

      };

      var INTERSECTED;

      init();
      animate();

      function init() {

        container = document.getElementById('background');

        camera = new THREE.PerspectiveCamera(70, window.innerWidth / window.innerHeight, 1, 10000);
        camera.position.set(0, 300, 500);

        scene = new THREE.Scene();
        scene.background = new THREE.Color(0xf0f0f0);

        for (var i = 0; i < 100; i++) {

          var particle = new THREE.Sprite(new THREE.SpriteCanvasMaterial({
            color: Math.random() * 0x808080 + 0x808080,
            program: programStroke
          }));
          particle.position.x = Math.random() * 800 - 400;
          particle.position.y = Math.random() * 800 - 400;
          particle.position.z = Math.random() * 800 - 400;
          particle.scale.x = particle.scale.y = Math.random() * 20 + 20;
          scene.add(particle);

        }

        //

        raycaster = new THREE.Raycaster();
        mouse = new THREE.Vector2();

        renderer = new THREE.CanvasRenderer();
        renderer.setPixelRatio(window.devicePixelRatio);
        renderer.setSize(window.innerWidth, window.innerHeight);
        container.appendChild(renderer.domElement);


        document.addEventListener('mousemove', onDocumentMouseMove, false);

        //

        window.addEventListener('resize', onWindowResize, false);

      }

      function onWindowResize() {

        camera.aspect = window.innerWidth / window.innerHeight;
        camera.updateProjectionMatrix();

        renderer.setSize(window.innerWidth, window.innerHeight);

      }

      function onDocumentMouseMove(event) {

        event.preventDefault();

        mouse.x = ( event.clientX / window.innerWidth ) * 2 - 1;
        mouse.y = -( event.clientY / window.innerHeight ) * 2 + 1;

      }

      //

      function animate() {

        requestAnimationFrame(animate);

        render();

      }

      var radius = 600;
      var theta = 0;

      function render() {

        // rotate camera

        theta += 0.1;

        camera.position.x = radius * Math.sin(THREE.Math.degToRad(theta));
        camera.position.y = radius * Math.sin(THREE.Math.degToRad(theta));
        camera.position.z = radius * Math.cos(THREE.Math.degToRad(theta));
        camera.lookAt(scene.position);

        camera.updateMatrixWorld();

        // find intersections

        raycaster.setFromCamera(mouse, camera);

        var intersects = raycaster.intersectObjects(scene.children);

        if (intersects.length > 0) {

          if (INTERSECTED != intersects[0].object) {

            if (INTERSECTED) INTERSECTED.material.program = programStroke;

            INTERSECTED = intersects[0].object;
            INTERSECTED.material.program = programFill;

          }

        } else {

          if (INTERSECTED) INTERSECTED.material.program = programStroke;

          INTERSECTED = null;

        }

        renderer.render(scene, camera);

      }
    }
  }
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
  h1, h2 {
    font-weight: normal;
  }

  ul {
    list-style-type: none;
    padding: 0;
  }

  li {
    display: inline-block;
    margin: 0 10px;
  }

  a {
    color: #35495E;
  }

  #background {
    position: absolute;
    width: 100%;
    height: 100%;
    top: 0px;
    z-index: -9;
  }

  body {
    overflow: hidden;
  }
</style>



