import Vue from 'vue'
import Router from 'vue-router'
import Hello from '@/components/Hello'
import Gallery from '@/components/Gallery'
import Tools from '@/components/Tools'
import MVTProcess from '@/components/tools/MVTProcess'

Vue.use(Router);

export default new Router({
  routes: [
    {
      path: '/',
      name: 'Hello',
      component: Hello
    },{
      path: '/gallery',
      name: 'Gallery',
      component: Gallery
    },{
      path: '/tools',
      name: 'Tools',
      component: Tools,
      children: [
        {
          // 当 /user/:id/profile 匹配成功，
          // UserProfile 会被渲染在 User 的 <router-view> 中
          path: 'mvt',
          component: MVTProcess
        }
      ]
    }
  ]
})



